import React from 'react';

const skillsData = [
  {
    name: 'HTML & CSS',
    description: 'Experienced in building responsive webpages.',
    links: [
      {
        href: 'https://www.freecodecamp.org/certification/fcc24f43bed-64e2-4997-8f56-da08871698cf/responsive-web-design',
        img: 'data:image/png;base64,',
        label: 'Certification',
      },
    ],
  },
  {
    name: 'JavaScript',
    level: 70,
    description: 'Strong understanding of core JS concepts and DOM manipulation.',
    links: [
      {
        href: 'https://developer.mozilla.org/en-US/docs/Web/JavaScript',
        img: 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/99/Unofficial_JavaScript_logo_2.svg/220px-Unofficial_JavaScript_logo_2.svg.png',
        label: 'JavaScript',
      },
      {
        href: 'https://javascript.info/',
        img: 'https://javascript.info/img/favicon/apple-touch-icon-precomposed.png',
        label: 'JS.info',
      },
    ],
  },
  {
    name: 'React',
    level: 60,
    description: 'Able to build component-based applications with hooks.',
    links: [
      {
        href: 'https://react.dev/',
        img: 'https://upload.wikimedia.org/wikipedia/commons/a/a7/React-icon.svg',
        label: 'React Docs',
      },
      {
        href: 'https://vitejs.dev/',
        img: 'https://vitejs.dev/logo.svg',
        label: 'Vite',
      },
      {
        href: 'https://github.com/amd-16',
        img: 'https://github.githubassets.com/images/modules/logos_page/GitHub-Mark.png',
        label: 'My GitHub',
      },
    ],
  },
];

const Skills = () => (
  <section
    id="Skills"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{
      fontFamily: "'Orbitron', sans-serif",
      background:
        'linear-gradient(180deg, rgba(26,26,26,0.85), rgba(11,31,63,0.90)), url(/images/background-image.jpg) no-repeat center center / cover',
      backgroundAttachment: 'fixed',
    }}
  >
    <h1 className="font-bold text-4xl text-white text-center mb-12">
      Skills
    </h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {skillsData.map((skill, i) => (
        <div
          key={i}
          className="rounded-xl p-6 shadow-md"
          style={{
            background: 'rgba(255,255,255,0.92)',
            borderLeft: '5px solid #0d6efd',
            backdropFilter: 'blur(6px)',
          }}
        >
          <h3 className="font-bold text-lg text-black">
            {skill.name}
          </h3>

          <p className="text-sm mt-2 text-gray-700">
            {skill.description}
          </p>

          <p className="text-sm mt-2 text-gray-500">
            Proficiency: {skill.level}%
          </p>

          {/* Progress bar */}
          <div
            style={{
              marginTop: '10px',
              height: '6px',
              borderRadius: '99px',
              background: '#e0e9f7',
              overflow: 'hidden',
            }}
          >
            <div
              style={{
                width: `${skill.level}%`,
                height: '100%',
                borderRadius: '99px',
                background: 'linear-gradient(90deg, #0d6efd, #4da3ff)',
              }}
            />
          </div>

          {/* Clickable icon links */}
          <div className="flex gap-3 mt-4 flex-wrap items-center">
            {skill.links.map((link, j) => (
              <a
                key={j}
                href={link.href}
                target="_blank"
                rel="noreferrer"
                title={link.label}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '6px',
                  padding: '4px 10px 4px 6px',
                  borderRadius: '8px',
                  border: '1.5px solid #0d6efd44',
                  background: '#f0f6ff',
                  textDecoration: 'none',
                  transition: 'transform 0.2s, box-shadow 0.2s',
                }}
                onMouseEnter={ev => {
                  ev.currentTarget.style.transform = 'translateY(-2px)';
                  ev.currentTarget.style.boxShadow = '0 4px 12px rgba(13,110,253,0.2)';
                }}
                onMouseLeave={ev => {
                  ev.currentTarget.style.transform = 'translateY(0)';
                  ev.currentTarget.style.boxShadow = 'none';
                }}
              >
                <img
                  src={link.img}
                  alt={link.label}
                  style={{ width: '22px', height: '22px', objectFit: 'contain', borderRadius: '4px' }}
                />
                <span style={{ fontSize: '11px', color: '#0d6efd', fontWeight: 'bold', letterSpacing: '0.5px' }}>
                  {link.label}
                </span>
              </a>
            ))}
          </div>
        </div>
      ))}
    </div>
  </section>
);

export default Skills;
